SELECT ?paper, ?year, ?dc_method_type_label, ?dc_method_name
        WHERE {
                ?paper orkgp:P31 ?contribution;
                       orkgp:P29 ?year.
                ?contribution a orkgc:C27001;
                              orkgp:P135046 ?serie.
                ?serie rdfs:label ?venue_name.

                ?contribution orkgp:P56008 ?data_collection.
                ?data_collection orkgp:P1005 ?dc_method;
                                 rdfs:label ?dc_label.
                ?dc_method orkgp:P94003 ?dc_method_type;
                           orkgp:P145012 ?dc_method_name.
                ?dc_method_type rdfs:label ?dc_method_type_label.

                FILTER(?dc_method_type_label = "secondary research"^^xsd:string)
                FILTER (?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)
        }

SELECT DISTINCT ?contribution ?paper ?paperLabel ?numberOfAnnotators ?NLPTaskTypeLabel ?annotatorAssignmentLabel ?levelOfExpertiseLabel ?annotatorIdentityLabel
    WHERE {
        ?paper orkgp:P31 ?contribution .
        ?contribution rdf:type orkgc:C121001;
                 orkgp:P181031 ?annotationProcess;
                 orkgp:P181003 ?NLPTask .

         ?NLPTask orkgp:P181004 ?NLPTaskType .
         ?annotationProcess orkgp:P181032 ?annotator .
         ?annotator orkgp:P59120 ?numberOfAnnotators;
                    orkgp:P181033 ?annotatorAssignment;
                    orkgp:P181034 ?levelOfExpertise;
                    orkgp:P181035 ?annotatorIdentity .

        OPTIONAL { ?NLPTaskType rdfs:label ?NLPTaskTypeLabel . }
        OPTIONAL {?paper rdfs:label ?paperLabel .}
        OPTIONAL {?annotatorAssignment rdfs:label ?annotatorAssignmentLabel .}
        OPTIONAL {?levelOfExpertise rdfs:label ?levelOfExpertiseLabel .}
        OPTIONAL {?annotatorIdentity rdfs:label ?annotatorIdentityLabel .}
    } ORDER BY ?paperLabel

SELECT ?paper, ?dc_method_type_label, ?dc_method_name
        WHERE {
                ?paper orkgp:P31 ?contribution;
                       orkgp:P29 ?year.
                ?contribution a orkgc:C27001;
                              orkgp:P135046 ?serie.
                ?serie rdfs:label ?venue_name.

                ?contribution orkgp:P56008 ?data_collection.
                ?data_collection orkgp:P1005 ?dc_method;
                                 rdfs:label ?dc_label.
                ?dc_method orkgp:P94003 ?dc_method_type;
                           orkgp:P145012 ?dc_method_name.
                ?dc_method_type rdfs:label ?dc_method_type_label.

                FILTER(?dc_method_type_label = "secondary research"^^xsd:string)
                FILTER (?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)
        }

SELECT DISTINCT ?contribution ?paper ?paperLabel ?baseline_typeLabel
    WHERE {
        ?paper orkgp:P31 ?contribution .
        ?contribution rdf:type orkgc:C121001;
             orkgp:HAS_EVALUATION ?evaluation .
        ?evaluation orkgp:P181051 ?baseline_comparison .
        ?baseline_comparison orkgp:P181052 ?baseline_type .

        OPTIONAL {?paper rdfs:label ?paperLabel .}
        OPTIONAL {?baseline_type rdfs:label ?baseline_typeLabel .}
    } ORDER BY ?contribution

SELECT DISTINCT ?contribution ?paper ?paperLabel ?NLPdataformatLabel
    WHERE {
        ?paper orkgp:P31 ?contribution .
        ?contribution rdf:type orkgc:C121001;
                 orkgp:P181011 ?NLPdataset .
        ?NLPdataset orkgp:P181022 ?NLPdatatype .
        ?NLPdatatype orkgp:P181023 ?NLPdataformat .

        OPTIONAL {?paper rdfs:label ?paperLabel .}
        OPTIONAL {?NLPdataformat rdfs:label ?NLPdataformatLabel .}
    } ORDER BY ?contribution

SELECT DISTINCT ?contribution ?paper ?paperLabel ?intercoderReliabilityMetricLabel
    WHERE {
        ?paper orkgp:P31 ?contribution .
        ?contribution rdf:type orkgc:C121001;
                 orkgp:P181031 ?annotationProcess .
        ?annotationProcess orkgp:P181041 ?annotationAgreement .
        ?annotationAgreement orkgp:P181042 ?intercoderReliabilityMetric .

        OPTIONAL {?paper rdfs:label ?paperLabel .}
        OPTIONAL {?intercoderReliabilityMetric rdfs:label ?intercoderReliabilityMetricLabel .}
    } ORDER BY ?contribution

SELECT ?paper ?paperLabel
       (GROUP_CONCAT(DISTINCT ?questionTypeLabel; separator=" | ") AS ?questionTypes)
WHERE {
    ?paper orkgp:P31 ?contribution .
    ?contribution a orkgc:C27001 ;
                    orkgp:P135046 ?venue .
    ?contribution orkgp:P37330 ?researchQuestion .
    ?researchQuestion orkgp:P41928 ?questionType .

    ?venue rdfs:label ?venue_name .
    OPTIONAL { ?paper rdfs:label ?paperLabel . }
    OPTIONAL { ?questionType rdfs:label ?questionTypeLabel . }
    FILTER(?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)
}
GROUP BY ?paper ?paperLabel
ORDER BY ?paperLabel

SELECT DISTINCT ?paper ?paperLabel ?dataType ?dataTypeLabel
WHERE {
    ?paper orkgp:P31 ?contribution .
    ?contribution a orkgc:C27001 ;
                    orkgp:P135046 ?venue .

    ?contribution orkgp:P56008 ?dataCollection .
    ?dataCollection orkgp:DATA ?researchData .
    ?researchData orkgp:P7055 ?dataType .
    ?venue rdfs:label ?venue_name .
    FILTER(?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)

    OPTIONAL { ?paper rdfs:label ?paperLabel . }
    OPTIONAL { ?dataType rdfs:label ?dataTypeLabel . }
}
ORDER BY ?paperLabel ?dataTypeLabel

SELECT DISTINCT ?paper ?paperLabel ?researchQuestion ?questionWording
WHERE {
    ?paper orkgp:P31 ?contribution .
    ?contribution a orkgc:C27001 ;
                    orkgp:P135046 ?venue .
    ?venue rdfs:label ?venue_name .
    ?contribution orkgp:P37330 ?researchQuestion .

    OPTIONAL { ?researchQuestion orkgp:P44139 ?questionWording . }
    ?paper rdfs:label ?paperLabel .

    FILTER NOT EXISTS {
        ?researchQuestion orkgp:P41928 ?questionType .
        ?questionType rdfs:label ?questionTypeLabel .
  }
    FILTER(?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)
}
ORDER BY ?paperLabel ?questionWording

SELECT DISTINCT ?paper ?paperLabel ?researchParadigm ?researchParadigmLabel
WHERE {
    ?paper orkgp:P31 ?contribution .
    ?contribution a orkgc:C27001.
    ?contribution orkgp:P57003 ?researchParadigm .
    ?contribution orkgp:P135046 ?venue .
    ?venue rdfs:label ?venue_name .

    FILTER(?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)
    OPTIONAL { ?paper rdfs:label ?paperLabel . }
    OPTIONAL { ?researchParadigm rdfs:label ?researchParadigmLabel . }
}
ORDER BY ?paperLabel ?researchParadigmLabel

SELECT DISTINCT ?paper ?paperLabel ?researchQuestion ?researchQuestionLabel ?questionWording
WHERE {
    ?paper orkgp:P31 ?contribution .
    ?contribution a orkgc:C27001 .
    ?contribution orkgp:P37330 ?researchQuestion .

    ?contribution orkgp:P135046 ?venue .
    ?venue rdfs:label ?venue_name .

    ?researchQuestion orkgp:P44139 ?questionWording .

    OPTIONAL {?researchQuestion rdfs:label ?researchQuestionLabel}
    OPTIONAL {?paper rdfs:label ?paperLabel .}

    FILTER(?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)
}
ORDER BY ?paperLabel ?questionWording

ASK {
  ?paper orkgp:P31 ?contribution .
  ?contribution a orkgc:C27001 ;
                  orkgp:P135046 ?venue .
  ?venue rdfs:label ?venue_name .

  ?contribution orkgp:P57004 ?researchQuestionAnswer .
  ?researchQuestionAnswer orkgp:P55039 ?highlightedInText .
  FILTER(?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)
}

SELECT ?paper ?paperLabel
       (GROUP_CONCAT(DISTINCT ?metricLabel; separator=", ") AS ?metrics)
WHERE {
  ?paper orkgp:P31 ?contribution .
  ?contribution a orkgc:C121001 ;
                orkgp:HAS_EVALUATION ?evaluation .

  OPTIONAL {?evaluation orkgp:P110006 ?metric .}

  OPTIONAL { ?paper rdfs:label ?paperLabel . }
  OPTIONAL { ?metric rdfs:label ?metricLabel . }
}
GROUP BY ?paper ?paperLabel
ORDER BY ?paperLabel

SELECT ?paper ?paperLabel
       (GROUP_CONCAT(DISTINCT ?baselineTypeLabel; separator=", ") AS ?baselineTypes)
WHERE {
  ?paper orkgp:P31 ?contribution .
  ?contribution a orkgc:C121001 .

  OPTIONAL {
    ?contribution orkgp:HAS_EVALUATION ?evaluation .
    ?evaluation orkgp:P181051 ?baselineComparison .
    ?baselineComparison orkgp:P181052 ?baselineType .
    OPTIONAL { ?baselineType rdfs:label ?baselineTypeLabel . }
  }

  OPTIONAL { ?paper rdfs:label ?paperLabel . }
}
GROUP BY ?paper ?paperLabel
ORDER BY ?paperLabel

SELECT
  ?reTask
  ?reTaskLabel
  ?nlpTaskInput
  ?nlpTaskInputLabel
  ?outputType
  ?outputTypeLabel
  (COUNT(DISTINCT ?paper) AS ?paperCount)
  (GROUP_CONCAT(DISTINCT ?paperLabel; SEPARATOR=" | ") AS ?papers)
WHERE {
  ?paper orkgp:P31 ?contribution .

  ?contribution a orkgc:C121001 ;
                orkgp:P181002 ?reTask ;
                orkgp:P181003 ?nlpTask .

  ?nlpTask orkgp:P181005 ?nlpTaskInput ;
           orkgp:P181006 ?nlpTaskOutput .

  ?nlpTaskOutput orkgp:P181007 ?outputType .

  OPTIONAL { ?paper rdfs:label ?paperLabel . }
  OPTIONAL { ?reTask rdfs:label ?reTaskLabel . }
  OPTIONAL { ?nlpTaskInput rdfs:label ?nlpTaskInputLabel . }
  OPTIONAL { ?outputType rdfs:label ?outputTypeLabel . }
}
GROUP BY
  ?reTask ?reTaskLabel
  ?nlpTaskInput ?nlpTaskInputLabel
  ?outputType ?outputTypeLabel
ORDER BY ?reTaskLabel DESC(?paperCount) ?nlpTaskInputLabel ?outputTypeLabel

SELECT DISTINCT
  ?paper
  ?paperLabel
  ?licenseType
  ?licenseTypeLabel
  ?locationType
  ?locationTypeLabel
  ?publicAvailabilityLabel
  ?url
WHERE {
  ?paper orkgp:P31 ?contribution .

  ?contribution a orkgc:C121001 ;
                orkgp:P181011 ?dataset .

  ?dataset orkgp:license ?license ;
           orkgp:P181028 ?datasetLocation .

  ?license orkgp:P181026 ?publicAvailability ;
           orkgp:P181027 ?licenseType .

  ?datasetLocation orkgp:P181030 ?locationType;
                    orkgp:P1003 ?url .

  OPTIONAL { ?paper rdfs:label ?paperLabel . }
  OPTIONAL { ?licenseType rdfs:label ?licenseTypeLabel . }
  OPTIONAL { ?locationType rdfs:label ?locationTypeLabel . }
  OPTIONAL { ?publicAvailability rdfs:label ?publicAvailabilityLabel . }

}
ORDER BY ?publicAvailabilityLabel ?paperLabel

SELECT
  ?paper
  ?paperLabel
  (GROUP_CONCAT(DISTINCT ?guidelineAvailabilityLabel; SEPARATOR=" | ") AS ?guidelineAvailabilities)
  (GROUP_CONCAT(DISTINCT ?measuredAgreement; SEPARATOR=" | ") AS ?measuredAgreements)
  (GROUP_CONCAT(DISTINCT ?metricLabel; SEPARATOR=" | ") AS ?metrics)
  (GROUP_CONCAT(DISTINCT ?conflictResolutionLabel; SEPARATOR=" | ") AS ?conflictResolutions)
WHERE {
  ?paper orkgp:P31 ?contribution .

  ?contribution a orkgc:C121001 ;
                orkgp:P181031 ?annotationProcess .

  ?annotationProcess orkgp:P181036 ?annotationScheme ;
                     orkgp:P181041 ?annotatorAgreement .

  ?annotationScheme orkgp:P181038 ?guidelineAvailability .
  ?annotatorAgreement orkgp:P181045 ?measuredAgreement ;
                      orkgp:P181042 ?metric ;
                      orkgp:P181044 ?conflictResolution .

  OPTIONAL { ?paper rdfs:label ?paperLabel . }
  OPTIONAL { ?guidelineAvailability rdfs:label ?guidelineAvailabilityLabel . }
  OPTIONAL { ?metric rdfs:label ?metricLabel . }
  OPTIONAL { ?conflictResolution rdfs:label ?conflictResolutionLabel . }
}
GROUP BY ?paper ?paperLabel
ORDER BY ?paperLabel

SELECT
    ?paper
    ?paperLabel
    ?baselineDetail
    (COUNT(DISTINCT ?baselineType) AS ?baselineTypeCount)
    (GROUP_CONCAT(DISTINCT ?baselineTypeLabel; SEPARATOR=" | ") AS ?baselineTypes)
WHERE {
    ?paper orkgp:P31 ?contribution .

    ?contribution a orkgc:C121001 ;
                orkgp:HAS_EVALUATION ?evaluation .

    ?evaluation orkgp:P181051 ?baselineComparison .

    ?baselineComparison orkgp:P181052 ?baselineType ;
                orkgp:P181053 ?baselineDetail .

    OPTIONAL { ?paper rdfs:label ?paperLabel . }
    OPTIONAL { ?baselineType rdfs:label ?baselineTypeLabel . }

}

GROUP BY ?paper ?paperLabel ?baselineDetail
HAVING(COUNT(DISTINCT ?baselineType) > 1)
ORDER BY ?paperLabel

SELECT
  ?paper
  ?paperLabel
  ?releaseFormats
  ?publicationTypes
  ?urls
  ?documentationTypes
WHERE {
  {
    SELECT DISTINCT ?paper ?paperLabel
    WHERE {
      ?paper orkgp:P31 ?contribution .
      ?contribution a orkgc:C121001 ;
                    orkgp:P181046 ?implementedApproach .
      ?implementedApproach orkgp:release ?release .
      OPTIONAL { ?paper rdfs:label ?paperLabel . }
    }
  }

  OPTIONAL {
    SELECT
      ?paper
      (GROUP_CONCAT(DISTINCT ?releaseFormatLabel; SEPARATOR=" | ") AS ?releaseFormats)
    WHERE {
      ?paper orkgp:P31 ?contribution .
      ?contribution a orkgc:C121001 ;
                    orkgp:P181046 ?implementedApproach .
      ?implementedApproach orkgp:release ?release .
      ?release orkgp:P181049 ?releaseFormat .
      OPTIONAL { ?releaseFormat rdfs:label ?releaseFormatLabel . }
    }
    GROUP BY ?paper
  }

  OPTIONAL {
    SELECT
      ?paper
      (GROUP_CONCAT(DISTINCT ?locationTypeLabel; SEPARATOR=" | ") AS ?publicationTypes)
    WHERE {
      ?paper orkgp:P31 ?contribution .
      ?contribution a orkgc:C121001 ;
                    orkgp:P181046 ?implementedApproach .
      ?implementedApproach orkgp:release ?release .
      ?release orkgp:P181029 ?locationType .
      OPTIONAL { ?locationType rdfs:label ?locationTypeLabel . }
    }
    GROUP BY ?paper
  }

  OPTIONAL {
    SELECT
      ?paper
      (GROUP_CONCAT(DISTINCT STR(?url); SEPARATOR=" | ") AS ?urls)
    WHERE {
      ?paper orkgp:P31 ?contribution .
      ?contribution a orkgc:C121001 ;
                    orkgp:P181046 ?implementedApproach .
      ?implementedApproach orkgp:release ?release .
      ?release orkgp:P1003 ?url .
    }
    GROUP BY ?paper
  }

  OPTIONAL {
    SELECT
      ?paper
      (GROUP_CONCAT(DISTINCT ?documentationTypeLabel; SEPARATOR=" | ") AS ?documentationTypes)
    WHERE {
      ?paper orkgp:P31 ?contribution .
      ?contribution a orkgc:C121001 ;
                    orkgp:P181046 ?implementedApproach .
      ?implementedApproach orkgp:P41835 ?documentationType .
      OPTIONAL { ?documentationType rdfs:label ?documentationTypeLabel . }
    }
    GROUP BY ?paper
  }
}
ORDER BY ?paperLabel

